(function(w){"use strict";const ID="triangle-area";function compute(x){const mode=x.mode||"base-height";if(mode==="base-height"){const base=Number(x.base),height=Number(x.height);if(!Number.isFinite(base)||!Number.isFinite(height)||base<0||height<0)return{error:"밑변과 높이에 0 이상의 숫자를 입력해 주세요."};return{mode,area:base*height/2}}if(mode==="three-sides"){let a=Number(x.a),b=Number(x.b),c=Number(x.c);if(!Number.isFinite(a)||!Number.isFinite(b)||!Number.isFinite(c)||a<=0||b<=0||c<=0)return{error:"세 변의 길이에 0보다 큰 숫자를 입력해 주세요."};const s=[a,b,c].sort((x,y)=>y-x);a=s[0];b=s[1];c=s[2];if(a>=b+c)return{error:"삼각형을 만들 수 없는 변의 길이입니다."};const product=(a+(b+c))*(c-(a-b))*(c+(a-b))*(a+(b-c));const area=.25*Math.sqrt(Math.max(0,product));return{mode,area,perimeter:a+b+c}}return{error:"계산 유형을 확인해 주세요."}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-tri-mode">계산 방식</label><select id="hm-tri-mode" class="hm-calc-select"><option value="base-height">밑변 × 높이 ÷ 2</option><option value="three-sides">세 변으로 계산 (헤론 공식)</option></select></div><div data-bh class="hm-calc-grid-2"><div class="hm-calc-field"><label for="hm-tri-base">밑변</label><input id="hm-tri-base" class="hm-calc-input" inputmode="decimal" placeholder="예: 10"></div><div class="hm-calc-field"><label for="hm-tri-height">높이</label><input id="hm-tri-height" class="hm-calc-input" inputmode="decimal" placeholder="예: 6"></div></div><div data-sss class="hm-calc-grid-2" hidden><div class="hm-calc-field"><label>변 a</label><input class="hm-calc-input" data-a inputmode="decimal" placeholder="예: 3"></div><div class="hm-calc-field"><label>변 b</label><input class="hm-calc-input" data-b inputmode="decimal" placeholder="예: 4"></div><div class="hm-calc-field"><label>변 c</label><input class="hm-calc-input" data-c inputmode="decimal" placeholder="예: 5"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">넓이 계산</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const q=s=>root.querySelector(s),mode=q("select"),bh=q("[data-bh]"),sss=q("[data-sss]"),base=q("#hm-tri-base"),height=q("#hm-tri-height"),a=q("[data-a]"),b=q("[data-b]"),c=q("[data-c]"),[go,reset]=root.querySelectorAll("button"),msg=q(".hm-calc-message"),res=q(".hm-calc-result");function sync(){const three=mode.value==="three-sides";bh.hidden=three;sss.hidden=!three}mode.addEventListener("change",sync);go.addEventListener("click",()=>{const r=compute({mode:mode.value,base:base.value,height:height.value,a:a.value,b:b.value,c:c.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");const detail=r.perimeter==null?"":`<dl><dt>둘레</dt><dd>${api.formatNumber(r.perimeter,10)}</dd></dl>`;api.setResult(res,api.resultCard("삼각형 넓이",api.formatNumber(r.area,10),detail));});reset.addEventListener("click",()=>{[base,height,a,b,c].forEach(v=>v.value="");mode.value="base-height";sync();api.setMessage(msg,"");api.clearResult(res);base.focus();});sync();}w.HM_CALC.register(ID,{compute,render});})(window);
